  ('dietitian-moex-01113', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '每日飲食指南使用方法步驟順序為何？①查出自己的生活活動強度  ②找出自己的健康體重', '["依熱量需求，查出自己的六大類飲食建議份數", "查出自己的熱量需求", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01114', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關飲食指標的敘述，下列何者正確？', '["維持多活動的生活習慣，每週累積至少150分鐘的中等費力身體活動", "男性飲酒每日不超過3杯，女性不超過2杯（每杯酒精10公克）", "了解自己每日熱量需求，適量多元飲食，以維持期待體重", "母乳哺餵嬰兒到6個月大，其後以米麥食品為主餵食"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01115', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '一位健康無慢性疾病長者70歲女性，身高155公分，體重52公斤，全職家庭主婦，每天做家事 並晨運快走1小時，根據國人膳食營養素參考攝取量及每日飲食指南，請選出下列正確每日飲食 建議：', '["熱量需求為1,400大卡", "未精製穀類份量為1碗", "油脂與堅果種子類7份", "鈣質建議攝取量1,200mg"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01116', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於DRIs，下列敘述何者錯誤？', '["AI是可滿足97-98%的健康人群", "每天所需要的營養素量RDA＝EAR＋2SD", "EAR為滿足健康人群中半數的人所需要的營養素量", "當數據不足無法定出值時，以健康者實際攝取量的數據衍算出來之營養素量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01117', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '民國106年公布之長期照顧服務法，下列敘述何者錯誤？', '["長期照顧服務的對象必須符合身體失能已經超過6個月以上者", "49歲以下身心障礙且失能者可納為長期照顧計畫服務對象", "營養師在居家照護的工作為居家營養評估及諮詢", "日間照顧屬於社區式的服務提供方式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01118', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一項不屬於營造母乳哺育親善環境之措施？', '["政府制定公共場所母乳哺育條例", "政府通過性別工作平等法", "醫院內鼓勵母嬰同室", "推廣母乳庫設置"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01119', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於市售包裝維生素礦物質類之錠狀膠囊狀食品營養標示，下列敘述何者錯誤？', '["該產品每顆（或錠、粒）所提供每日基準值百分比", "應符合「市售包裝食品營養標示規範」所需之營養標示規定", "維生素A、維生素D及維生素E應另加註以國際單位（IU）之含量標示", "欲敘述維生素、礦物質之生理功能，則其每日最低攝取量需達每日基準值15%以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01120', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某偏鄉國中全校班級數10班，自設廚房辦理學校午餐，依規定下列何者需要立即改善？', '["該校未聘用營養師", "供應當日新鮮麵包與饅頭，品質衛生符合標準，但未取得優良食品認證", "午餐留樣皆有標示日期、餐別，置於攝氏7度以下，冷藏保存24小時", "購買有「合格屠宰證明」的生鮮肉品，但沒有臺灣生鮮豬肉TFP（TaiwanFreshPork）標章"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01121', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '「校園飲品及點心販售範圍」規定，下列敘述何者錯誤？', '["鈉含量應在300毫克以下", "一份供應熱量應在250大卡以下", "添加糖的供應熱量應在10%以下", "油、糖個別所占之熱量不得超過總熱量之30%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01122', 'dietitian', 'dietitian-moex-110-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據教育部「學校午餐食物內容及營養基準」高中生午餐每日食物內容目標值，下列那一項不符合？', '["全穀雜糧類中應有1/3以上為未精製", "低脂乳品類每週供應2份", "魚類供應每週至少1份", "水果類每餐1份"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "e1aa55548509", "answer_pdf_sha1": "470380484a31", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
